#include <stdio.h>
#include <assert.h>

int main() {
    int n, m;
    scanf("%d %d", &n, &m);

    assert(1 <= n && n <= 100);
    assert(1 <= m && m <= 100);

    int mat[n][m];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            scanf("%d", &mat[i][j]);
        }
    }

    for (int i = n - 1; i >= 0; i--) {
        for (int j = 0; j < m; j++) {
            printf("%d ", mat[i][j]);
        }
        printf("\n");
    }

    return 0;
}

